    private bool _saving;
    private bool _showSuccess;

    protected override void OnParametersSet()
    {
        _mutedSet = [.. MutedChannels];
    }

    private bool IsChannelMuted(string channel) => _mutedSet.Contains(channel);

    private void ToggleChannel(string channel, bool muted)
    {
        if (muted) _mutedSet.Add(channel);
        else _mutedSet.Remove(channel);
    }

    private async Task Save()
    {
        _saving = true;
        await OnSave.InvokeAsync((EmailNotifications, PushNotifications, WeeklyDigest, [.. _mutedSet]));
        _saving = false;
        _showSuccess = true;
        _ = HideSuccessAfterDelay();
    }

    private async Task HideSuccessAfterDelay()
    {
        await Task.Delay(3000);
        _showSuccess = false;
        await InvokeAsync(StateHasChanged);
    }
}
