toolArgs.file_text:
@namespace sv_f744ce8c4fbc48a9a0003c5278f57baa.Components.Pages.Settings

<div class="profile-section">
    <h4>Profile Settings</h4>
    <p class="text-muted">Manage your personal information</p>

    <div class="avatar-area mb-4">
        <img src="@AvatarUrl" alt="Avatar" class="avatar-preview" />
        <div class="avatar-url text-muted small mt-1">@AvatarUrl</div>
    </div>

    <div class="mb-3">
        <label class="form-label">Display Name</label>
        <input type="text" class="form-control" @bind="DisplayName" />
    </div>

    <div class="mb-3">
        <label class="form-label">Email</label>
        <input type="email" class="form-control" @bind="Email" />
    </div>

    <div class="mb-3">
        <label class="form-label">Bio</label>
        <textarea class="form-control" rows="4" @bind="Bio"></textarea>
    </div>

    <div class="d-flex gap-2">
        <button class="btn btn-primary" @onclick="Save" disabled="@_saving">
            @if (_saving) { <span class="spinner-border spinner-border-sm me-1"></span> }
            Save Changes
        </button>
        <button class="btn btn-outline-secondary" @onclick="Discard">Discard Changes</button>
    </div>

    @if (_showSuccess)
    {
        <div class="alert alert-success mt-3 fade-in" role="alert">
            ✅ Profile saved successfully!
        </div>
    }
</div>

@code {
    [Parameter] public string DisplayName { get; set; } = "";
    [Parameter] public string Email { get; set; } = "";
    [Parameter] public string AvatarUrl { get; set; } = "";
    [Parameter] public string Bio { get; set; } = "";
    [Parameter] public EventCallback<(string DisplayName, string Email, string Bio)> OnSave { get; set; }
    [Parameter] public EventCallback OnDiscard { get; set; }

    private bool _saving;
    private bool _showSuccess;

    private async Task Save()
    {
        _saving = true;
        await OnSave.InvokeAsync((DisplayName, Email, Bio));
        _saving = false;
        _showSuccess = true;
        _ = HideSuccessAfterDelay();
    }

    private async Task HideSuccessAfterDelay()
    {
        await Task.Delay(3000);
        _showSuccess = false;
        await InvokeAsync(StateHasChanged);
    }

    private async Task Discard()
    {
        _showSuccess = false;
        await OnDiscard.InvokeAsync();
    }
}

