+            <h6 class="card-title">Notification Channels</h6>
+
+            <div class="form-check form-switch mb-3">
+                <input class="form-check-input" type="checkbox" id="emailNotif"
+                       checked="@EmailNotifications"
+                       @onchange="e => EmailNotifications = (bool)e.Value!" />
+                <label class="form-check-label" for="emailNotif">
+                    📧 Email Notifications
+                </label>
+            </div>
+
+            <div class="form-check form-switch mb-3">
+                <input class="form-check-input" type="checkbox" id="pushNotif"
+                       checked="@PushNotifications"
+                       @onchange="e => PushNotifications = (bool)e.Value!" />
+                <label class="form-check-label" for="pushNotif">
+                    📱 Push Notifications
+                </label>
+            </div>
+
+            <div class="form-check form-switch">
+                <input class="form-check-input" type="checkbox" id="weeklyDigest"
+                       checked="@WeeklyDigest"
+                       @onchange="e => WeeklyDigest = (bool)e.Value!" />
+                <label class="form-check-label" for="weeklyDigest">
+                    📰 Weekly Digest
+                </label>
+            </div>
+        </div>
+    </div>
+
+    <div class="card mb-4">
+        <div class="card-body">
+            <h6 class="card-title">Muted Channels</h6>
+            <p class="small text-muted">Check channels you want to mute</p>
+            @foreach (var channel in MutedChannels)
+            {
+                <div class="form-check mb-2">
+                    <input class="form-check-input" type="checkbox" id="@($"ch-{channel}")"
+                           checked="@IsChannelMuted(channel)"
+                           @onchange="e => ToggleChannel(channel, (bool)e.Value!)" />
+                    <label class="form-check-label" for="@($"ch-{channel}")">@channel</label>
+                </div>
+            }
+        </div>
+    </div>
+
+    <button class="btn btn-primary" @onclick="Save" disabled="@_saving">
+        @if (_saving) { <span class="spinner-border spinner-border-sm me-1"></span> }
+        Save Preferences
+    </button>
+
+    @if (_showSuccess)
+    {
+        <div class="alert alert-success mt-3 fade-in" role="alert">
+            ✅ Notification preferences saved!
+        </div>
+    }
+</div>
+
+@code {
+    [Parameter] public bool EmailNotifications { get; set; }
+    [Parameter] public bool PushNotifications { get; set; }
+    [Parameter] public bool WeeklyDigest { get; set; }
+    [Parameter] public List<string> MutedChannels { get; set; } = [];
+    [Parameter] public EventCallback<(bool Email, bool Push, bool Digest, List<string> Muted)> OnSave { get; set; }
+
+    private HashSet<string> _mutedSet = [];
+    private bool _saving;
+    private bool _showSuccess;
+
+    protected override void OnParametersSet()
+    {
+        _mutedSet = [.. MutedChannels];
+    }
+
+    private bool IsChannelMuted(string channel) => _mutedSet.Contains(channel);
+
+    private void ToggleChannel(string channel, bool muted)
+    {
+        if (muted) _mutedSet.Add(channel);
+        else _mutedSet.Remove(channel);
+    }
+
+    private async Task Save()
+    {
+        _saving = true;
+        await OnSave.InvokeAsync((EmailNotifications, PushNotifications, WeeklyDigest, [.. _mutedSet]));
+        _saving = false;
+        _showSuccess = true;
+        _ = HideSuccessAfterDelay();
+    }
+
+    private async Task HideSuccessAfterDelay()
+    {
+        await Task.Delay(3000);
+        _showSuccess = false;
+        await InvokeAsync(StateHasChanged);
+    }
+}
+

