@namespace sv_f744ce8c4fbc48a9a0003c5278f57baa.Components.Pages.Settings

<div class="card mb-4">
    <div class="card-header d-flex justify-content-between align-items-center"
         style="cursor: pointer" @onclick="ToggleExpanded">
        <h6 class="mb-0">🔑 Change Password</h6>
        <span class="expand-icon">@(_expanded ? "▲" : "▼")</span>
    </div>
    @if (_expanded)
    {
        <div class="card-body">
            <div class="mb-3">
                <label class="form-label">Current Password</label>
                <input type="password" class="form-control" @bind="_currentPassword" />
            </div>
            <div class="mb-3">
                <label class="form-label">New Password</label>
                <input type="password" class="form-control" @bind="_newPassword" />
            </div>
            <div class="mb-3">
                <label class="form-label">Confirm New Password</label>
                <input type="password" class="form-control" @bind="_confirmPassword" />
            </div>

            @if (!string.IsNullOrEmpty(_error))
            {
                <div class="alert alert-danger py-2">@_error</div>
            }
            @if (_showSuccess)
            {
                <div class="alert alert-success py-2">✅ Password updated successfully!</div>
            }

            <button class="btn btn-warning" @onclick="UpdatePassword" disabled="@_updating">
                @if (_updating) { <span class="spinner-border spinner-border-sm me-1"></span> }
                Update Password
            </button>
        </div>
    }
</div>

@code {
    [Parameter] public EventCallback<(string Current, string New)> OnChangePassword { get; set; }

    private bool _expanded;
    private string _currentPassword = "";
    private string _newPassword = "";
    private string _confirmPassword = "";
    private string? _error;
    private bool _updating;
    private bool _showSuccess;

    private void ToggleExpanded() => _expanded = !_expanded;

    private async Task UpdatePassword()
    {
        _error = null;
        _showSuccess = false;

        if (string.IsNullOrWhiteSpace(_currentPassword) || string.IsNullOrWhiteSpace(_newPassword))
        {
            _error = "All password fields are required.";
            return;
        }

        if (_newPassword != _confirmPassword)
        {
            _error = "New password and confirmation do not match.";
            return;
        }

        if (_newPassword.Length < 8)
        {
            _error = "New password must be at least 8 characters.";
            return;
        }

        _updating = true;
        await OnChangePassword.InvokeAsync((_currentPassword, _newPassword));
        _updating = false;
        _showSuccess = true;
        _currentPassword = "";
        _newPassword = "";
        _confirmPassword = "";
    }
}

