@namespace sv_f744ce8c4fbc48a9a0003c5278f57baa.Components.Pages.Settings

@if (_visible)
{
    <div class="modal-backdrop show"></div>
    <div class="modal d-block" tabindex="-1">
        <div class="modal-dialog modal-dialog-centered">
            <div class="modal-content">
                <div class="modal-header">
                    <h5 class="modal-title">Revoke Session</h5>
                    <button type="button" class="btn-close" @onclick="Cancel"></button>
                </div>
                <div class="modal-body">
                    <p>Are you sure you want to revoke the session on <strong>@_device</strong> from <strong>@_location</strong>?</p>
                    <p class="text-muted small">This will sign out the device immediately.</p>
                </div>
                <div class="modal-footer">
                    <button class="btn btn-secondary" @onclick="Cancel">Cancel</button>
                    <button class="btn btn-danger" @onclick="Confirm">Revoke Session</button>
                </div>
            </div>
        </div>
    </div>
}

@code {
    private bool _visible;
    private string _sessionId = "";
    private string _device = "";
    private string _location = "";
    private TaskCompletionSource<bool>? _tcs;

    public Task<bool> ShowAsync(string sessionId, string device, string location)
    {
        _sessionId = sessionId;
        _device = device;
        _location = location;
        _visible = true;
        _tcs = new TaskCompletionSource<bool>();
        StateHasChanged();
        return _tcs.Task;
    }

    private void Confirm()
    {
        _visible = false;
        _tcs?.TrySetResult(true);
    }

    private void Cancel()
    {
        _visible = false;
        _tcs?.TrySetResult(false);
    }
}

