@namespace sv_f744ce8c4fbc48a9a0003c5278f57baa.Components.Pages.Settings

<div class="appearance-section">
    <h4>Appearance Settings</h4>
    <p class="text-muted">Customize how the app looks</p>

    <div class="row">
        <div class="col-md-7">
            <div class="card mb-4">
                <div class="card-body">
                    <h6 class="card-title">Theme</h6>
                    @foreach (var theme in new[] { "Light", "Dark", "System" })
                    {
                        <div class="form-check mb-2">
                            <input class="form-check-input" type="radio" name="theme"
                                   id="@($"theme-{theme}")" value="@theme"
                                   checked="@(Theme == theme)"
                                   @onchange="() => Theme = theme" />
                            <label class="form-check-label" for="@($"theme-{theme}")">@theme</label>
                        </div>
                    }
                </div>
            </div>

            <div class="card mb-4">
                <div class="card-body">
                    <h6 class="card-title">Font Size</h6>
                    @foreach (var size in new[] { "Small", "Medium", "Large" })
                    {
                        <div class="form-check form-check-inline">
                            <input class="form-check-input" type="radio" name="fontSize"
                                   id="@($"fs-{size}")" value="@size"
                                   checked="@(FontSize == size)"
                                   @onchange="() => FontSize = size" />
                            <label class="form-check-label" for="@($"fs-{size}")">@size</label>
                        </div>
                    }
                </div>
            </div>

            <div class="card mb-4">
                <div class="card-body">
                    <h6 class="card-title">Language</h6>
                    <select class="form-select" value="@Language" @onchange="e => Language = (string)e.Value!">
                        @foreach (var lang in Languages)
                        {
                            <option value="@lang">@lang</option>
                        }
                    </select>
                </div>
            </div>

            <div class="card mb-4">
                <div class="card-body d-flex justify-content-between align-items-center">
                    <div>
                        <h6 class="mb-0">Compact Mode</h6>
                        <small class="text-muted">Reduce spacing and padding</small>
                    </div>
                    <div class="form-check form-switch">
                        <input class="form-check-input" type="checkbox" id="compactMode"
                               checked="@CompactMode"
                               @onchange="e => CompactMode = (bool)e.Value!" />
                    </div>
                </div>
            </div>

            <button class="btn btn-primary" @onclick="Save" disabled="@_saving">
                @if (_saving) { <span class="spinner-border spinner-border-sm me-1"></span> }
                Save
            </button>

            @if (_showSuccess)
            {
                <div class="alert alert-success mt-3 fade-in" role="alert">
                    ✅ Appearance settings saved!
                </div>
            }
        </div>

        <div class="col-md-5">
            <div class="card">
                <div class="card-header">
                    <h6 class="mb-0">Live Preview</h6>
                </div>
                <div class="card-body preview-area @GetPreviewClasses()">
                    <h5 class="preview-title">Sample Heading</h5>
                    <p class="preview-text">This is how your content will look with the selected settings.</p>
                    <div class="d-flex gap-2 mt-3">
                        <button class="btn btn-primary btn-sm">Primary</button>
                        <button class="btn btn-outline-secondary btn-sm">Secondary</button>
                    </div>
                    <div class="mt-3">
                        <span class="badge bg-info me-1">Tag 1</span>
                        <span class="badge bg-success me-1">Tag 2</span>
                        <span class="badge bg-warning">Tag 3</span>
                    </div>
                </div>
            </div>
        </div>
    </div>
</div>

@code {
    [Parameter] public string Theme { get; set; } = "Light";
    [Parameter] public string FontSize { get; set; } = "Medium";
    [Parameter] public string Language { get; set; } = "English";
    [Parameter] public bool CompactMode { get; set; }
    [Parameter] public EventCallback<(string Theme, string FontSize, string Language, bool CompactMode)> OnSave { get; set; }

    private static readonly string[] Languages = ["English", "Spanish", "French", "German", "Japanese", "Chinese", "Portuguese"];

    private bool _saving;
    private bool _showSuccess;

    private string GetPreviewClasses()
    {
        var classes = new List<string>();
        classes.Add(Theme switch { "Dark" => "preview-dark", "System" => "preview-system", _ => "preview-light" });
        classes.Add(FontSize switch { "Small" => "preview-font-sm", "Large" => "preview-font-lg", _ => "preview-font-md" });
        if (CompactMode) classes.Add("preview-compact");
        return string.Join(" ", classes);
    }

    private async Task Save()
    {
        _saving = true;
        await OnSave.InvokeAsync((Theme, FontSize, Language, CompactMode));
        _saving = false;
        _showSuccess = true;
        _ = HideSuccessAfterDelay();
    }

    private async Task HideSuccessAfterDelay()
    {
        await Task.Delay(3000);
        _showSuccess = false;
        await InvokeAsync(StateHasChanged);
    }
}

.appearance-section {
    max-width: 800px;
}

.preview-area {
    border-radius: 0.375rem;
    padding: 1.5rem;
    transition: all 0.3s ease;
    min-height: 200px;
}

.preview-light {
    background-color: #ffffff;
    color: #212529;
}

.preview-dark {
    background-color: #1a1a2e;
    color: #e0e0e0;
}

.preview-dark .btn-primary {
    background-color: #4a6cf7;
    border-color: #4a6cf7;
}

.preview-dark .btn-outline-secondary {
    color: #adb5bd;
    border-color: #adb5bd;
}

.preview-system {
    background: linear-gradient(135deg, #ffffff 50%, #1a1a2e 50%);
    color: #495057;
}

.preview-font-sm {
    font-size: 0.8rem;
}

.preview-font-md {
    font-size: 1rem;
}

.preview-font-lg {
    font-size: 1.2rem;
}

.preview-compact {
    padding: 0.75rem !important;
    line-height: 1.2;
}

.preview-compact .preview-title {
    margin-bottom: 0.25rem;
}

.preview-compact .preview-text {
    margin-bottom: 0.25rem;
}

.fade-in {
    animation: fadeIn 0.3s ease-in;
}

@keyframes fadeIn {
    from { opacity: 0; transform: translateY(-4px); }
    to { opacity: 1; transform: translateY(0); }
}

