arguments.file_text:
@page "/settings"
@using sv_f744ce8c4fbc48a9a0003c5278f57baa.Models
@using sv_f744ce8c4fbc48a9a0003c5278f57baa.Components.Pages.Settings
@rendermode InteractiveServer
@inject ISettingsService SettingsService

<PageTitle>Settings</PageTitle>

<div class="settings-layout">
    <div class="settings-nav">
        <SettingsSidebar ActiveSection="@_activeSection" OnSectionChanged="s => _activeSection = s" />
    </div>

    <div class="settings-content p-4">
        @if (_loading)
        {
            <div class="d-flex justify-content-center py-5">
                <div class="spinner-border text-primary" role="status">
                    <span class="visually-hidden">Loading...</span>
                </div>
            </div>
        }
        else
        {
            @switch (_activeSection)
            {
                case "Profile":
                    <ProfileSection DisplayName="@_profile!.DisplayName"
                                    Email="@_profile.Email"
                                    AvatarUrl="@_profile.AvatarUrl"
                                    Bio="@_profile.Bio"
                                    OnSave="SaveProfile"
                                    OnDiscard="DiscardProfile" />
                    break;

                case "Notifications":
                    <NotificationsSection EmailNotifications="@_notifPrefs!.EmailNotifications"
                                          PushNotifications="@_notifPrefs.PushNotifications"
                                          WeeklyDigest="@_notifPrefs.WeeklyDigest"
                                          MutedChannels="@_notifPrefs.MutedChannels"
                                          OnSave="SaveNotifications" />
                    break;

                case "Security":
                    <SecuritySection TwoFactorEnabled="@_security!.TwoFactorEnabled"
                                     LastPasswordChange="@_security.LastPasswordChange"
                                     Sessions="@_security.Sessions"
                                     OnChangePassword="ChangePassword"
                                     OnTwoFactorToggled="ToggleTwoFactor"
                                     OnRevoke="RevokeSession" />
                    break;

                case "Appearance":
                    <AppearanceSection Theme="@_appearance!.Theme"
                                       FontSize="@_appearance.FontSize"
                                       Language="@_appearance.Language"
                                       CompactMode="@_appearance.CompactMode"
                                       OnSave="SaveAppearance" />
                    break;
            }
        }
    </div>
</div>

@code {
    private string _activeSection = "Profile";
    private bool _loading = true;

    private UserProfile? _profile;
    private NotificationPrefs? _notifPrefs;
    private SecuritySettings? _security;
    private AppearanceSettings? _appearance;

    protected override async Task OnInitializedAsync()
    {
        await LoadAllData();
        _loading = false;
    }

    private async Task LoadAllData()
    {
        var profileTask = SettingsService.GetProfileAsync();
        var notifTask = SettingsService.GetNotificationPrefsAsync();
        var securityTask = SettingsService.GetSecuritySettingsAsync();
        var appearanceTask = SettingsService.GetAppearanceAsync();

        await Task.WhenAll(profileTask, notifTask, securityTask, appearanceTask);

        _profile = profileTask.Result;
        _notifPrefs = notifTask.Result;
        _security = securityTask.Result;
        _appearance = appearanceTask.Result;
    }

    private async Task SaveProfile((string DisplayName, string Email, string Bio) data)
    {
        var updated = _profile! with { DisplayName = data.DisplayName, Email = data.Email, Bio = data.Bio };
        await SettingsService.SaveProfileAsync(updated);
        _profile = updated;
    }

    private async Task DiscardProfile()
    {
        _profile = await SettingsService.GetProfileAsync();
    }

    private async Task SaveNotifications((bool Email, bool Push, bool Digest, List<string> Muted) data)
    {
        var updated = new NotificationPrefs(data.Email, data.Push, data.Digest, data.Muted);
        await SettingsService.SaveNotificationPrefsAsync(updated);
        _notifPrefs = updated;
    }

    private async Task ChangePassword((string Current, string New) data)
    {
        await SettingsService.ChangePasswordAsync(data.Current, data.New);
        _security = await SettingsService.GetSecuritySettingsAsync();
    }

    private async Task ToggleTwoFactor(bool enabled)
    {
        _security = _security! with { TwoFactorEnabled = enabled };
        StateHasChanged();
        await Task.CompletedTask;
    }

    private async Task RevokeSession(string sessionId)
    {
        await SettingsService.RevokeSessionAsync(sessionId);
        _security = await SettingsService.GetSecuritySettingsAsync();
    }

    private async Task SaveAppearance((string Theme, string FontSize, string Language, bool CompactMode) data)
    {
        var updated = new AppearanceSettings(data.Theme, data.FontSize, data.Language, data.CompactMode);
        await SettingsService.SaveAppearanceAsync(updated);
        _appearance = updated;
    }
}

.settings-layout {
    display: flex;
    min-height: calc(100vh - 3.5rem);
    margin: -1.5rem;
    background-color: #fff;
}

.settings-nav {
    width: 220px;
    flex-shrink: 0;
}

.settings-content {
    flex: 1;
    overflow-y: auto;
    background-color: #fff;
}

@page "/settings"
