                </div>
            </div>
        }
        else
        {
            @switch (_activeSection)
            {
                case "Profile":
                    <ProfileSection DisplayName="@_profile!.DisplayName"
                                    Email="@_profile.Email"
                                    AvatarUrl="@_profile.AvatarUrl"
                                    Bio="@_profile.Bio"
                                    OnSave="SaveProfile"
                                    OnDiscard="DiscardProfile" />
                    break;

                case "Notifications":
                    <NotificationsSection EmailNotifications="@_notifPrefs!.EmailNotifications"
                                          PushNotifications="@_notifPrefs.PushNotifications"
