@code {
    private string _activeSection = "Profile";
    private bool _loading = true;

    private UserProfile? _profile;
    private NotificationPrefs? _notifPrefs;
    private SecuritySettings? _security;
    private AppearanceSettings? _appearance;

    protected override async Task OnInitializedAsync()
    {
        await LoadAllData();
        _loading = false;
    }

    private async Task LoadAllData()
    {
        var profileTask = SettingsService.GetProfileAsync();
        var notifTask = SettingsService.GetNotificationPrefsAsync();
        var securityTask = SettingsService.GetSecuritySettingsAsync();
        var appearanceTask = SettingsService.GetAppearanceAsync();

        await Task.WhenAll(profileTask, notifTask, securityTask, appearanceTask);

        _profile = profileTask.Result;
        _notifPrefs = notifTask.Result;
        _security = securityTask.Result;
        _appearance = appearanceTask.Result;
    }

    private async Task SaveProfile((string DisplayName, string Email, string Bio) data)
    {
        var updated = _profile! with { DisplayName = data.DisplayName, Email = data.Email, Bio = data.Bio };
        await SettingsService.SaveProfileAsync(updated);
        _profile = updated;
    }

    private async Task DiscardProfile()
    {
        _profile = await SettingsService.GetProfileAsync();
    }

    private async Task SaveNotifications((bool Email, bool Push, bool Digest, List<string> Muted) data)
    {
        var updated = new NotificationPrefs(data.Email, data.Push, data.Digest, data.Muted);
        await SettingsService.SaveNotificationPrefsAsync(updated);
        _notifPrefs = updated;
    }

    private async Task ChangePassword((string Current, string New) data)
    {
        await SettingsService.ChangePasswordAsync(data.Current, data.New);
        _security = await SettingsService.GetSecuritySettingsAsync();
    }

    private async Task ToggleTwoFactor(bool enabled)
    {
        _security = _security! with { TwoFactorEnabled = enabled };
        StateHasChanged();
        await Task.CompletedTask;
    }

    private async Task RevokeSession(string sessionId)
    {
        await SettingsService.RevokeSessionAsync(sessionId);
        _security = await SettingsService.GetSecuritySettingsAsync();
    }

    private async Task SaveAppearance((string Theme, string FontSize, string Language, bool CompactMode) data)
    {
        var updated = new AppearanceSettings(data.Theme, data.FontSize, data.Language, data.CompactMode);
        await SettingsService.SaveAppearanceAsync(updated);
        _appearance = updated;
    }
}

